exercises.solution:
function stringify(value: string | number | boolean | null | undefined): string {
  if (value == null) {
    return "N/A";
  }
  if (typeof value === "string") {
    return value;
  }
  if (typeof value === "number") {
    return value.toFixed(1);
  }
  return String(value);
}

console.log(stringify("hello"));
console.log(stringify(3.14159));
console.log(stringify(true));
console.log(stringify(null));
console.log(stringify(undefined));

