exercises.solution:
function safeDivide(a: number | string, b: number | string): string {
  const numA = typeof a === "string" ? Number(a) : a;
  const numB = typeof b === "string" ? Number(b) : b;

  if (isNaN(numA) || isNaN(numB)) {
    return "Error: invalid input";
  }
  if (numB === 0) {
    return "Error: division by zero";
  }
  return (numA / numB).toFixed(2);
}

console.log(safeDivide(10, 3));
console.log(safeDivide("20", "4"));
console.log(safeDivide(10, 0));
console.log(safeDivide("abc", 5));

