exercises.solution:
class NotFoundError extends Error {
  constructor(public path: string) {
    super(`Not found: ${path}`);
  }
}

class AuthError extends Error {
  constructor(public userId: string) {
    super(`Unauthorized: ${userId}`);
  }
}

function describeError(err: Error): string {
  if (err instanceof NotFoundError) {
    return `404 - Path not found: ${err.path}`;
  }
  if (err instanceof AuthError) {
    return `401 - Unauthorized user: ${err.userId}`;
  }
  return `General error: ${err.message}`;
}

console.log(describeError(new NotFoundError("/api/users")));
console.log(describeError(new AuthError("user-42")));
console.log(describeError(new Error("Unknown error")));

