type Circle = { radius: number };
type Rectangle = { width: number; height: number };
type Triangle = { base: number; height: number };

function getArea(shape: Circle | Rectangle | Triangle): string {
  if ("radius" in shape) {
    return (Math.PI * shape.radius  2).toFixed(2);
  }
  if ("width" in shape) {
    return (shape.width * shape.height).toFixed(2);
  }
  return (0.5 * shape.base * shape.height).toFixed(2);
}

console.log(getArea({ radius: 5 }));
console.log(getArea({ width: 4, height: 6 }));
console.log(getArea({ base: 10, height: 3 }));

